package agent

import (
	"context"
	"encoding/json"
	"fmt"
	"os"
	"time"

	agentlib "github.com/DocumentDrivenDX/fizeau"
)

// Public event-type strings emitted by agentlib.FizeauService.Execute, mirrored
// from CONTRACT-003 §"Event JSON shapes". Kept as constants here so the
// drain loop does not have to import the agent's internal/harnesses
// package (which is module-private).
const (
	serviceEventRoutingDecision = "routing_decision"
	serviceEventFinal           = "final"
)

// ServiceEvent payload types are now aliases to the upstream v0.8.0 public
// types (agent-f0bc5467). DDx previously maintained byte-for-byte shadow
// copies of these structs because CONTRACT-003 hadn't published them; that
// left the consumer carrying stream-adjacent knowledge and drifted whenever
// upstream shapes changed. With v0.8.0 the types are public and stable.
//
// Aliases rather than an outright delete so existing call sites keep
// working without a sweep. New code can (and should) use agentlib types
// directly.
type (
	serviceFinalData = agentlib.ServiceFinalData
)

type serviceRoutingActual struct {
	Harness                     string
	Provider                    string
	Model                       string
	PredictedPower              int
	PredictedSpeedTPS           float64
	PredictedCostUSDPer1kTokens float64
	PredictedCostSource         string
}

// useNewAgentPath reports whether RunAgent should dispatch to the new
// agentlib.FizeauService.Execute path. Default is on. Set the env var
// DDX_USE_NEW_AGENT_PATH=0 (or "false") to disable as an emergency escape
// hatch.
func useNewAgentPath() bool {
	switch os.Getenv("DDX_USE_NEW_AGENT_PATH") {
	case "0", "false", "FALSE", "False":
		return false
	default:
		return true
	}
}

// runAgentViaService is the new RunAgent dispatch path that drives the
// agent through agentlib.FizeauService.Execute and drains the resulting event
// channel into a DDx Result. Old in-package code paths (RunAgent legacy
// loop, embeddedCompactionConfig, buildAgentProvider, findTool,
// wrapProviderWithDeadlines, stall + compaction-stuck circuit breakers)
// stay in place; this function does NOT call them.
//
// Stall detection: we delegate to the agent's StallPolicy. The agent
// emits a stall event then a final event with Status="stalled".
func runAgentViaService(r *Runner, opts RunArgs) (*Result, error) {
	promptText, err := r.resolvePrompt(opts)
	if err != nil {
		return nil, err
	}

	model := r.resolveModel(opts, "agent")
	timeout := r.resolveTimeout(opts)
	wallClock := r.resolveWallClock(opts)

	wd := opts.WorkDir
	if wd == "" {
		wd, _ = os.Getwd()
	}

	// Construct the service. Reuses NewServiceFromWorkDir so provider/model
	// routing data lands on the agent the same way every other DDx command
	// constructs it (see serviceconfig.go).
	svc, err := NewServiceFromWorkDir(wd)
	if err != nil {
		return nil, fmt.Errorf("agent: build service: %w", err)
	}

	// Resolve where to write the per-request session log.
	logDir := opts.SessionLogDir
	if logDir == "" {
		logDir = r.Config.SessionLogDir
	}
	if logDir == "" {
		logDir = DefaultLogDir
	}

	providerTimeout := ResolveProviderRequestTimeout(wd, opts.Provider, model, 0)

	// Build the public ExecuteRequest per CONTRACT-003.
	req := agentlib.ServiceExecuteRequest{
		Prompt:          promptText,
		Model:           model,
		Provider:        opts.Provider,
		Harness:         "agent",
		ModelRef:        opts.ModelRef,
		Reasoning:       agentlib.Reasoning(opts.Effort),
		Permissions:     opts.Permissions,
		WorkDir:         wd,
		Timeout:         wallClock,
		IdleTimeout:     timeout,
		ProviderTimeout: providerTimeout,
		SessionLogDir:   logDir,
		Metadata:        opts.Correlation,
		Role:            opts.Role,
		CorrelationID:   opts.CorrelationID,
	}

	parentCtx := opts.Context
	if parentCtx == nil {
		parentCtx = context.Background()
	}
	ctx, cancel := context.WithCancel(parentCtx)
	defer cancel()

	start := time.Now()
	events, err := svc.Execute(ctx, req)
	if err != nil {
		return nil, fmt.Errorf("agent: execute: %w", err)
	}

	final, routing, actualPower, _ := drainServiceEvents(events)
	elapsed := time.Since(start)

	result := &Result{
		Harness:    "agent",
		Model:      model,
		DurationMS: int(elapsed.Milliseconds()),
	}
	if routing != nil {
		result.Provider = routing.Provider
		if routing.Model != "" {
			result.Model = routing.Model
		}
		result.PredictedPower = routing.PredictedPower
		result.PredictedSpeedTPS = routing.PredictedSpeedTPS
		result.PredictedCostUSDPer1kTokens = routing.PredictedCostUSDPer1kTokens
		result.PredictedCostSource = routing.PredictedCostSource
	}
	if actualPower > 0 {
		result.ActualPower = actualPower
	}
	if final != nil {
		// Normalized final text from the upstream harness (agent-32e8ff5e).
		result.Output = final.FinalText
		if final.Usage != nil {
			// v0.9.1: Usage fields became *int so the API can distinguish
			// "harness reported zero" from "harness didn't report". Treat
			// nil as zero for DDx's int-valued result struct.
			if final.Usage.InputTokens != nil {
				result.InputTokens = *final.Usage.InputTokens
			}
			if final.Usage.OutputTokens != nil {
				result.OutputTokens = *final.Usage.OutputTokens
			}
			if final.Usage.TotalTokens != nil {
				result.Tokens = *final.Usage.TotalTokens
			}
		}
		if final.CostUSD > 0 {
			result.CostUSD = final.CostUSD
		}
		result.ExitCode = final.ExitCode
		result.Error = final.Error
		if final.RoutingActual != nil {
			if result.Provider == "" {
				result.Provider = final.RoutingActual.Provider
			}
			if final.RoutingActual.Model != "" {
				result.Model = final.RoutingActual.Model
			}
		}
		if final.SessionLogPath != "" {
			// surface as session ID for downstream cross-reference (mirrors
			// the legacy path's AgentSessionID population).
			result.AgentSessionID = final.SessionLogPath
		}
	}
	result.Error = appendProviderTimeoutHint(result.Error, providerTimeout)

	promptSource := opts.PromptSource
	if promptSource == "" {
		if opts.PromptFile != "" {
			promptSource = opts.PromptFile
		} else {
			promptSource = "inline"
		}
	}
	r.logSession(result, len(promptText), promptText, promptSource, opts.Correlation)
	r.recordRoutingOutcome(result, elapsed, opts)
	return result, nil
}

// drainServiceEvents reads service events and returns the final-event payload,
// the routing decision (when present in the routing_decision start event), the
// power of the selected model (0 when the routing_decision event does not
// include candidate power components), and any canonical progress payloads
// emitted by the service.
func drainServiceEvents(events <-chan agentlib.ServiceEvent) (*serviceFinalData, *serviceRoutingActual, int, []agentlib.ServiceProgressData) {
	var final *serviceFinalData
	var routing *serviceRoutingActual
	var routingPower int
	var progress []agentlib.ServiceProgressData

	for ev := range events {
		switch string(ev.Type) {
		case serviceEventRoutingDecision:
			var payload struct {
				Harness    string `json:"harness"`
				Provider   string `json:"provider"`
				Model      string `json:"model"`
				Candidates []struct {
					Model              string  `json:"model"`
					Eligible           bool    `json:"eligible"`
					CostUSDPer1kTokens float64 `json:"cost_usd_per_1k_tokens"`
					CostSource         string  `json:"cost_source"`
					Components         struct {
						Power    int     `json:"power"`
						SpeedTPS float64 `json:"speed_tps"`
					} `json:"components"`
				} `json:"candidates"`
			}
			if err := json.Unmarshal(ev.Data, &payload); err == nil {
				routing = &serviceRoutingActual{
					Harness:  payload.Harness,
					Provider: payload.Provider,
					Model:    payload.Model,
				}
				for _, c := range payload.Candidates {
					if c.Eligible && c.Model == payload.Model {
						routingPower = c.Components.Power
						routing.PredictedPower = c.Components.Power
						routing.PredictedSpeedTPS = c.Components.SpeedTPS
						routing.PredictedCostUSDPer1kTokens = c.CostUSDPer1kTokens
						routing.PredictedCostSource = c.CostSource
						break
					}
				}
			}
		case agentlib.ServiceEventTypeProgress:
			var data agentlib.ServiceProgressData
			if err := json.Unmarshal(ev.Data, &data); err == nil {
				progress = append(progress, data)
			}
		case serviceEventFinal:
			var data serviceFinalData
			if err := json.Unmarshal(ev.Data, &data); err == nil {
				final = &data
			}

	// ExecuteBeadTmpSubdir is the subdirectory under $TMPDIR in which
	// execute-bead creates its isolated worktrees. Keeping them outside
	// the project tree prevents child processes (tests, hooks) running
	// inside the worktree from mutating the parent repository's
	// .git/config via inherited GIT_DIR.
	ExecuteBeadTmpSubdir = "ddx-exec-wt"
)

// executeBeadWorktreePath returns the absolute path where an execute-bead
// isolated worktree for (beadID, attemptID) should live.
func executeBeadWorktreePath(beadID, attemptID string) string {
	base := os.Getenv("DDX_EXEC_WT_DIR")
	if base == "" {
		base = filepath.Join(os.TempDir(), ExecuteBeadTmpSubdir)
	}
	return filepath.Join(base, ExecuteBeadWtPrefix+beadID+"-"+attemptID)
}

// RealGitOps implements GitOps via os/exec git commands.
type RealGitOps struct{}

func (r *RealGitOps) HeadRev(dir string) (string, error) {
	return r.ResolveRev(dir, "HEAD")
}

func (r *RealGitOps) ResolveRev(dir, rev string) (string, error) {
	out, err := internalgit.Command(context.Background(), dir, "rev-parse", rev).Output()
	if err != nil {
		return "", fmt.Errorf("git rev-parse %s: %w", rev, err)
	}
	return strings.TrimSpace(string(out)), nil
}

func (r *RealGitOps) WorktreeAdd(dir, wtPath, rev string) error {
	out, err := internalgit.Command(context.Background(), dir, "worktree", "add", "--detach", wtPath, rev).CombinedOutput()
	if err != nil {
		return fmt.Errorf("git worktree add: %s: %w", strings.TrimSpace(string(out)), err)
	}
	return nil
}

func (r *RealGitOps) WorktreeRemove(dir, wtPath string) error {
	_ = internalgit.Command(context.Background(), dir, "worktree", "remove", "--force", wtPath).Run()
	return nil
}

func (r *RealGitOps) WorktreeList(dir string) ([]string, error) {
	out, err := internalgit.Command(context.Background(), dir, "worktree", "list", "--porcelain").Output()
	if err != nil {
		return nil, fmt.Errorf("git worktree list: %w", err)
	}
	var paths []string
	for _, line := range strings.Split(string(out), "\n") {
		if strings.HasPrefix(line, "worktree ") {
			paths = append(paths, strings.TrimPrefix(line, "worktree "))
		}
	}
	return paths, nil
}

func (r *RealGitOps) WorktreePrune(dir string) error {
	return internalgit.Command(context.Background(), dir, "worktree", "prune").Run()
}

// UpdateRef updates ref in dir to sha via `git update-ref`.
func (r *RealGitOps) UpdateRef(dir, ref, sha string) error {
	out, err := internalgit.Command(context.Background(), dir, "update-ref", ref, sha).CombinedOutput()
	if err != nil {
		return fmt.Errorf("git update-ref %s: %s: %w", ref, strings.TrimSpace(string(out)), err)
	}
	return nil
}

// DeleteRef removes ref from dir via `git update-ref -d`.
func (r *RealGitOps) DeleteRef(dir, ref string) error {
	out, err := internalgit.Command(context.Background(), dir, "update-ref", "-d", ref).CombinedOutput()
	if err != nil {
		return fmt.Errorf("git update-ref -d %s: %s: %w", ref, strings.TrimSpace(string(out)), err)
	}
	return nil
}

// IsDirty reports whether dir has any uncommitted changes (tracked modifications or untracked files).
func (r *RealGitOps) IsDirty(dir string) (bool, error) {
	out, _ := internalgit.Command(context.Background(), dir, "status", "--porcelain").Output()
	return len(bytes.TrimSpace(out)) > 0, nil
}

func dirtyWorktreePaths(dir string) []string {
	out, err := internalgit.Command(context.Background(), dir, "status", "--porcelain", "--untracked-files=all").Output()
	if err != nil {
		return nil
	}
	var paths []string
	seen := map[string]bool{}
	for _, line := range strings.Split(string(out), "\n") {
		line = strings.TrimSpace(line)
		if line == "" || len(line) < 4 {
			continue
		}
		path := strings.TrimSpace(line[3:])
		if idx := strings.Index(path, " -> "); idx >= 0 {
			path = strings.TrimSpace(path[idx+4:])
		}
		if path == "" || seen[path] {
			continue
		}
		seen[path] = true
		paths = append(paths, path)
	}
	return paths
}

// EvidenceLandExcludePathspecs returns git pathspec-exclusion fragments
// applied when landEvidence / VerifyCleanWorktree stage the evidence
// directory. Only excludes the multi-thousand-line embedded session log
// (the single file that actually explodes past provider context
// limits). prompt.md, usage.json, manifest.json, and result.json remain
// tracked — they are small and serve the audit-trail contract. The
// gitignore written by `ddx init` already treats .ddx/executions/*/
// embedded as ignored; this pathspec is defence-in-depth for force-add
// paths.
//
// Regression anchor: ddx-39e27896 — session logs landed as tracked
// evidence caused retry prompts to balloon past 2M+ tokens and crash
// every provider with n_keep > n_ctx.
func EvidenceLandExcludePathspecs() []string {
	return []string{
		":(exclude,glob).ddx/executions/*/embedded/**",
	}
}

// EvidenceReviewExcludePathspecs returns git pathspec-exclusion fragments
// applied when review-prompt synthesis runs `git show <rev>` over the
// evidence commit. Broader than EvidenceLandExcludePathspecs: excludes
// prompt.md and usage.json too, because even though they're tracked for
// audit, they're execution-artifact noise from the reviewer's
// perspective — the reviewer wants to see the implementation diff, not
// the prior attempt's prompt or token counters. This also protects
// against old commits (pre-fix) that committed the session log
// directly.
//
// Regression anchor: ddx-39e27896.
func EvidenceReviewExcludePathspecs() []string {
	return []string{
		":(exclude,glob).ddx/executions/*/embedded/**",
		":(exclude,glob).ddx/executions/*/prompt.md",
		":(exclude,glob).ddx/executions/*/usage.json",
	}
}

// SynthesizeCommit stages real file changes, explicitly excluding harness noise
// paths, and creates a commit with msg as the commit message. Returns (true, nil)
// when a commit was made, (false, nil) when nothing real remained to commit
// after exclusions, and (false, err) on failure.
func (r *RealGitOps) SynthesizeCommit(dir, msg string) (bool, error) {
	// Do NOT list already-gitignored paths (.ddx/agent-logs, .ddx/workers) as
	// :(exclude) pathspecs. Git treats a path named by :(exclude) as explicitly
	// referenced, so when the path is also .gitignored git emits "The following
	// paths are ignored by one of your .gitignore files" AND exits 1 — even
	// though the pathspec is trying to SKIP it. Paths already in .gitignore are
	// excluded by default; excludes here are only for paths that would
	// otherwise be tracked.
	addArgs := []string{
		"add", "-A", "--",
		".",
	}
	addArgs = append(addArgs, synthesizeCommitExcludePathspecs(dir)...)
	if err := internalgit.Command(context.Background(), dir, addArgs...).Run(); err != nil {
		return false, fmt.Errorf("staging changes: %w", err)
	}
	statusOut, _ := internalgit.Command(context.Background(), dir, "diff", "--cached", "--name-only").Output()
	if len(bytes.TrimSpace(statusOut)) == 0 {
		return false, nil
	}
	if msg == "" {
		msg = "chore: execute-bead synthesized result commit"
	}
	out, err := internalgit.Command(context.Background(), dir, "commit", "-m", msg).CombinedOutput()
	if err != nil {
		return false, fmt.Errorf("synthesize commit: %s: %w", strings.TrimSpace(string(out)), err)
	}
	return true, nil
}

func synthesizeCommitExcludePathspecs(dir string) []string {
	candidates := []struct {
		pathspec    string
		ignoreProbe string
	}{
		{
			pathspec:    ":(exclude).ddx/executions/*/embedded",
			ignoreProbe: ".ddx/executions/.ddx-check-ignore/embedded",
		},
		{
			pathspec:    ":(exclude).ddx/executions/*/no_changes_rationale.txt",
			ignoreProbe: ".ddx/executions/.ddx-check-ignore/no_changes_rationale.txt",
		},
		{
			pathspec:    ":(exclude).claude/skills",
			ignoreProbe: ".claude/skills",
		},
		{
			pathspec:    ":(exclude).agents/skills",
			ignoreProbe: ".agents/skills",
		},
	}

	pathspecs := make([]string, 0, len(candidates))
	for _, c := range candidates {
		if isGitIgnored(dir, c.ignoreProbe) {
			continue
		}
		pathspecs = append(pathspecs, c.pathspec)
	}
	return pathspecs
}

func isGitIgnored(dir, path string) bool {
	err := internalgit.Command(context.Background(), dir, "check-ignore", "-q", "--", path).Run()
	return err == nil
}

// GenerateAttemptID generates a unique attempt identifier.
func GenerateAttemptID() string {
	b := make([]byte, 4)
	_, _ = rand.Read(b)
	return time.Now().UTC().Format("20060102T150405") + "-" + hex.EncodeToString(b)
